import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void basic() {
        int[][] input = {{101, 78701}, {102, 78702}, {103, 78701}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(Set.of(78701, 78702), result.keySet());
        assertEquals(List.of(101, 103), result.get(78701));
        assertEquals(List.of(102), result.get(78702));
    }

    @Test
    void empty() {
        Map<Integer, List<Integer>> result = new Solution().customersByZip(new int[][]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleCustomer() {
        int[][] input = {{999, 10001}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(Set.of(10001), result.keySet());
        assertEquals(List.of(999), result.get(10001));
    }

    @Test
    void allSameZip() {
        // adversarial: every customer in the same ZIP
        int[][] input = {{1, 90210}, {2, 90210}, {3, 90210}, {4, 90210}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(Set.of(90210), result.keySet());
        assertEquals(List.of(1, 2, 3, 4), result.get(90210));
    }

    @Test
    void eachZipDistinct() {
        // every customer has a unique ZIP — each bucket has exactly one customer
        int[][] input = {{10, 11111}, {20, 22222}, {30, 33333}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(Set.of(11111, 22222, 33333), result.keySet());
        assertEquals(List.of(10), result.get(11111));
        assertEquals(List.of(20), result.get(22222));
        assertEquals(List.of(30), result.get(33333));
    }

    @Test
    void preservesCustomerOrder() {
        // customers within a ZIP must appear in input order
        int[][] input = {{5, 77001}, {3, 77001}, {9, 77001}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(List.of(5, 3, 9), result.get(77001));
    }

    @Test
    void alternatingZips() {
        // keys alternate in input to exercise interleaved bucketing
        int[][] input = {{1, 10000}, {2, 20000}, {3, 10000}, {4, 20000}, {5, 10000}};
        Map<Integer, List<Integer>> result = new Solution().customersByZip(input);
        assertEquals(Set.of(10000, 20000), result.keySet());
        assertEquals(List.of(1, 3, 5), result.get(10000));
        assertEquals(List.of(2, 4), result.get(20000));
    }
}
